# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

import os
from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import secrets
import time
from datetime import datetime, timedelta
import hashlib

app = Flask(__name__)

# In-memory storage for nonces and sessions
# In production, use Redis or a database
nonces = {}
sessions = {}

# Session expiry time (24 hours)
SESSION_EXPIRY = 24 * 60 * 60

# Nonce expiry time (5 minutes)
NONCE_EXPIRY = 5 * 60

# Initialize Web3
w3 = Web3()

def generate_nonce():
    """Generate a random nonce for signature verification"""
    return secrets.token_hex(16)

def create_message(nonce, address):
    """Create a message to be signed"""
    return f"Sign this message to authenticate with our service.\n\nNonce: {nonce}\nAddress: {address}"

def clean_expired_nonces():
    """Remove expired nonces"""
    current_time = time.time()
    expired = [addr for addr, data in nonces.items() 
               if current_time - data['timestamp'] > NONCE_EXPIRY]
    for addr in expired:
        del nonces[addr]

def clean_expired_sessions():
    """Remove expired sessions"""
    current_time = time.time()
    expired = [token for token, data in sessions.items() 
               if current_time - data['timestamp'] > SESSION_EXPIRY]
    for token in expired:
        del sessions[token]

def verify_signature(message, signature, expected_address):
    """Verify an Ethereum signature"""
    try:
        # Encode the message
        message_hash = encode_defunct(text=message)
        
        # Recover the address from the signature
        recovered_address = w3.eth.account.recover_message(message_hash, signature=signature)
        
        # Compare addresses (case-insensitive)
        return recovered_address.lower() == expected_address.lower()
    except Exception as e:
        print(f"Signature verification error: {e}")
        return False

def generate_session_token():
    """Generate a unique session token"""
    return secrets.token_urlsafe(32)

@app.route('/api/auth/nonce', methods=['POST'])
def get_nonce():
    """Request a nonce for signing"""
    data = request.get_json()
    
    if not data or 'address' not in data:
        return jsonify({'error': 'Address is required'}), 400
    
    address = data['address']
    
    # Validate Ethereum address
    if not w3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    # Clean expired nonces
    clean_expired_nonces()
    
    # Generate nonce
    nonce = generate_nonce()
    
    # Store nonce with timestamp
    nonces[address.lower()] = {
        'nonce': nonce,
        'timestamp': time.time()
    }
    
    # Create message to sign
    message = create_message(nonce, address)
    
    return jsonify({
        'nonce': nonce,
        'message': message
    }), 200

@app.route('/api/auth/verify', methods=['POST'])
def verify_and_authenticate():
    """Verify signature and create session"""
    data = request.get_json()
    
    if not data or 'address' not in data or 'signature' not in data:
        return jsonify({'error': 'Address and signature are required'}), 400
    
    address = data['address']
    signature = data['signature']
    
    # Validate Ethereum address
    if not w3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    # Clean expired nonces
    clean_expired_nonces()
    
    # Check if nonce exists
    address_lower = address.lower()
    if address_lower not in nonces:
        return jsonify({'error': 'No nonce found. Please request a new nonce'}), 401
    
    nonce_data = nonces[address_lower]
    nonce = nonce_data['nonce']
    
    # Check if nonce is expired
    if time.time() - nonce_data['timestamp'] > NONCE_EXPIRY:
        del nonces[address_lower]
        return jsonify({'error': 'Nonce expired. Please request a new nonce'}), 401
    
    # Create the expected message
    message = create_message(nonce, address)
    
    # Verify signature
    if not verify_signature(message, signature, address):
        return jsonify({'error': 'Invalid signature'}), 401
    
    # Remove used nonce
    del nonces[address_lower]
    
    # Clean expired sessions
    clean_expired_sessions()
    
    # Create session
    session_token = generate_session_token()
    sessions[session_token] = {
        'address': address_lower,
        'timestamp': time.time()
    }
    
    return jsonify({
        'token': session_token,
        'address': address,
        'message': 'Authentication successful'
    }), 200

@app.route('/api/auth/verify-token', methods=['POST'])
def verify_token():
    """Verify a session token"""
    auth_header = request.headers.get('Authorization')
    
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({'error': 'Missing or invalid authorization header'}), 401
    
    token = auth_header.split(' ')[1]
    
    # Clean expired sessions
    clean_expired_sessions()
    
    if token not in sessions:
        return jsonify({'error': 'Invalid or expired token'}), 401
    
    session_data = sessions[token]
    
    # Check if session is expired
    if time.time() - session_data['timestamp'] > SESSION_EXPIRY:
        del sessions[token]
        return jsonify({'error': 'Session expired'}), 401
    
    return jsonify({
        'valid': True,
        'address': session_data['address']
    }), 200

@app.route('/api/auth/logout', methods=['POST'])
def logout():
    """Logout and invalidate session"""
    auth_header = request.headers.get('Authorization')
    
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({'error': 'Missing or invalid authorization header'}), 401
    
    token = auth_header.split(' ')[1]
    
    if token in sessions:
        del sessions[token]
    
    return jsonify({'message': 'Logged out successfully'}), 200

